from smolagents import Agent, tool
from typing import Literal

class SafeToolAgent(Agent):
    def __init__(self, tools):
        super().__init__(tools=tools)

    def validate_and_call(self, tool_call):
        tool_name = tool_call['name']
        args = tool_call['arguments']

        # Strict type checking
        if tool_name == 'calculator' and not isinstance(args.get('x'), (int, float)):
            return "Error: calculator requires numeric input"

        try:
            return self.tools[tool_name](**args)
        except Exception as e:
            return f"Tool error: {str(e)}"

@tool
def calculator(x: float, operation: Literal['add', 'multiply'] = 'add') -> float:
    return x * 2 if operation == 'multiply' else x + 1

safe_agent = SafeToolAgent(tools=[calculator])
